UPDATE
MST.TB_AUDIT_DHCP_MST A
SET

		A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}


		 ,A.NIP_BLOCK_CNT = #{nipBlockCnt, jdbcType=NUMERIC}


		, A.NIP_CNT = #{nipCnt, jdbcType=NUMERIC}


		, A.NMAX_PEAK = #{nmaxPeak, jdbcType=INTEGER}


		, A.NMIN_PEAK = #{nminPeak, jdbcType=INTEGER}


		, A.NDHCP_RANGE_DAYS = #{ndhcpRangeDays, jdbcType=INTEGER}


		, A.BFALG = #{bfalg, jdbcType=CHAR}


		, A.SCOMMENT = #{scomment, jdbcType=VARCHAR}




	, A.DMODIFY_DT = sysdate
WHERE A.NAUDIT_DHCP_MST_SEQ = #{nauditDhcpMstSeq, jdbcType=BIGINT}

UPDATE
MST.TB_AUDIT_DHCP_MST A
SET

		 A.BFALG = #{bfalg, jdbcType=CHAR}


		, A.DMODIFY_DT = #{dmodifyDt, jdbcType=TIMESTAMP}


		, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

	, A.DMODIFY_DT = sysdate
WHERE A.NAUDIT_DHCP_MST_SEQ = #{nauditDhcpMstSeq, jdbcType=BIGINT}

mapper.select:
SELECT
FROM MST.TB_AUDIT_DHCP_MST A
WHERE A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD(+) AND A.NLVL_MST_SEQ = C.NLVL_MST_SEQ(+) AND C.SSVC_LINE_TYPE_CD = D.SSVC_LINE_TYPE_CD(+) AND C.SSVC_GROUP_CD = E.SLVL_CD(+) AND C.SSVC_OBJ_CD = F.SLVL_CD(+) AND A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD(+) AND A.SOFFICE_CD = G.SLVL_CD(+) AND A.STOP_NODE_CD = H.SLVL_CD(+) AND A.NAUDIT_DHCP_MST_SEQ = #{nauditDhcpMstSeq}

SELECT
,A.NDCHP_RANGE_DAYS AS NDHCP_RANGE_DAYS FROM MST.TB_AUDIT_DHCP_MST A
WHERE A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD(+) AND A.NLVL_MST_SEQ = C.NLVL_MST_SEQ(+) AND C.SSVC_LINE_TYPE_CD = D.SSVC_LINE_TYPE_CD(+) AND C.SSVC_GROUP_CD = E.SLVL_CD(+) AND C.SSVC_OBJ_CD = F.SLVL_CD(+) AND A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD(+) AND A.SOFFICE_CD = G.SLVL_CD(+) AND A.STOP_NODE_CD = I.SLVL_CD(+) AND A.NAUDIT_DHCP_MST_SEQ = #{item.nauditDhcpMstSeq}

SELECT
A.RNUM FROM ( SELECT
ROWNUM RNUM FROM ( SELECT
FROM MST.TB_AUDIT_DHCP_MST A
AND A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD(+) AND A.NLVL_MST_SEQ = C.NLVL_MST_SEQ(+) AND C.SSVC_LINE_TYPE_CD = D.SSVC_LINE_TYPE_CD(+) AND C.SSVC_GROUP_CD = E.SLVL_CD(+) AND C.SSVC_OBJ_CD = F.SLVL_CD(+) AND A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD(+) AND A.SOFFICE_CD = G.SLVL_CD(+) AND A.STOP_NODE_CD = H.SLVL_CD(+)
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
GROUP BY
,SSVC_GROUP_NM ,STOP_NODE_NM ,B.SSVC_LINE_TYPE_NM ,SOFFICE_NM ,BAUDIT_NM ,BOPTIMIZE_NM ,BFALG_NM ,SSVC_OBJ_NM
) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT count(1) totalCount FROM MST.TB_AUDIT_DHCP_MST A
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}

SELECT A.SOFFICE_CD AS code , B.SLVL_NM as name FROM MST.TB_AUDIT_DHCP_MST A , MST.TB_LVL_CD B WHERE 1=1 AND A.SOFFICE_CD = B.SLVL_CD(+) AND A.SOFFICE_CD IN ( SELECT SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB WHERE SLVL_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
)) GROUP BY A.SOFFICE_CD, B.SLVL_NM ORDER BY B.SLVL_NM

SELECT A.SOFFICE_CD AS sofficeCd , B.SLVL_NM as sofficeNm FROM MST.TB_AUDIT_DHCP_MST A , MST.TB_LVL_CD B WHERE 1=1 AND A.SOFFICE_CD = B.SLVL_CD(+) AND A.SOFFICE_CD IN ( SELECT SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB WHERE SLVL_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
)) GROUP BY A.SOFFICE_CD, B.SLVL_NM ORDER BY B.SLVL_NM
